`,Bt(t.p,{children:["Multimodal Emotion Recognition (MER) aims to understand human affect from text, audio, and visual signals, but real-world multimodal inputs are often incomplete or contradictory across modalities, making reliable prediction difficult. Although recent Multimodal Large Language Models (MLLMs) have shown strong potential for MER, their internal decision-making under modality conflict and missingness remains underexplored. To study this systematically, we introduce ",Bt(t.strong,{children:"EmoMM"}),", a benchmark covering aligned, conflict, and missing-modality settings, and use it to evaluate multiple MLLMs. Our analysis reveals a ",Bt(t.strong,{children:"Video Contribution Collapse (VCC)"})," phenomenon, where models sharply underutilize video evidence in challenging cases, largely due to video-token redundancy and stable modality preference. To address this issue, we further propose ",Bt(t.strong,{children:"CHASE"}),", a lightweight conflict-aware inference-time attention steering method that improves cross-modal evidence integration and enhances robustness under conflict and missing-modality conditions."]}),`
`,Bt(t.p,{children:Bt(t.img,{src:"./EmoMM_subset.png",alt:"Overview of the EmoMM benchmark"})}),`
`,Bt(t.p,{children:Bt(t.em,{children:"Figure 1. Overview of the EmoMM benchmark. Left: subset split of EmoMM into EmoMM-Align, EmoMM-Conflict, and EmoMM-Missing. Right: example instances illustrating the three subsets."})})]})}function pG(e={}){const{wrapper:t}=e.components||{};return t?Bt(t,{...e,children:Bt(T0,{...e})}):T0(e)}const vG={__name:"Overview",setup(e){return(t,n)=>{const o=He("el-divider"),a=He("el-col"),l=He("el-row");return E(),D("div",null,[H(o),H(l,{justify:"center"},{default:Y(()=>[H(a,{xs:24,sm:20,md:16,lg:12,xl:12},{default:Y(()=>[H(s(pG))]),_:1})]),_:1})])}}};function M0(e){const t={em:"em",h1:"h1",img:"img",p:"p",...e.components};return Bt(Le,{children:[Bt(t.h1,{children:"Benchmark"}),`
`,Bt(t.p,{children:"Real-world multimodal emotion recognition often faces two practical challenges: cross-modal conflict and missing modalities. However, many existing datasets only provide a single multimodal label and assume that all modalities are always available, which makes these settings difficult to study systematically. To address this, we introduce EmoMM, a benchmark designed for multimodal emotion recognition under both modality conflict and modality missingness. EmoMM provides both unimodal and multimodal emotion annotations, enabling evaluation under full-modality and missing-modality conditions."}),`
`,Bt(t.p,{children:Bt(t.img,{src:"./EmoMM_Flowchart.png",alt:"Overview of the EmoMM benchmark"})}),`
`,Bt(t.p,{children:Bt(t.em,{children:"Figure 2. Overview of the EmoMM construction pipeline: data curation for CH-SIMS v2.0 and CMU-MOSI, single-modality human labeling for independent unimodal annotations on CMU-MOSI (CH-SIMS v2.0 provides unimodal labels), followed by statistical analysis and subset partitioning under sentiment conflicts and modality missingness."})}),`
`,Bt(t.p,{children:"We analyze the label distributions of ground truth, text, audio, and video, and measure the consistency between different sources. The results show that text has the strongest agreement with the ground-truth label, suggesting that lexical information often provides the clearest emotional signal. In contrast, text and video show the weakest agreement, reflecting that visual emotion cues are often more subtle and harder to interpret."}),`
